def find_filled_block(grid, color):
    h,w=grid.shape
    for size in range(1,min(h,w)+1):
        for r in range(h-size+1):
            for c in range(w-size+1):
                block = grid[r:r+size,c:c+size]
                if np.all(block==color):
                    return size, r, c
    return None
print(find_filled_block(grid1,2))

def find_block(grid,color, hsize, wsize):
    H,W=grid.shape
    for r in range(H-hsize+1):
        for c in range(W-wsize+1):
            if np.all(grid[r:r+hsize,c:c+wsize]==color):
                return (r,c)
    return None
