def list_rects(grid,color):
    H,W=grid.shape
    rects=[]
    for hsize in range(2,H+1):
        for wsize in range(2,W+1):
            for r in range(H-hsize+1):
                for c in range(W-wsize+1):
                    sub=grid[r:r+hsize,c:c+wsize]
                    if np.all(sub==color):
                        rects.append((hsize,wsize,r,c))
    return rects
