from collections import deque
grid=grid_test
H,W=grid.shape
visited=np.zeros_like(grid,bool)
components=[]
for r in range(H):
    for c in range(W):
        if not visited[r,c] and grid[r,c]==8:
            q=deque([(r,c)])
            visited[r,c]=True
            cells=[]
            while q:
                x,y=q.popleft()
                cells.append((x,y))
                for dx,dy in [(1,0),(-1,0),(0,1),(0,-1)]:
                    nx,ny=x+dx,y+dy
                    if 0<=nx<H and 0<=ny<W and not visited[nx,ny] and grid[nx,ny]==8:
                        visited[nx,ny]=True
                        q.append((nx,ny))
            components.append(cells)
len(components)

comp_info=[]
for cells in components:
    rs=[x for x,_ in cells]
    cs=[y for _,y in cells]
    rmin,rmax=min(rs),max(rs)
    cmin,cmax=min(cs),max(cs)
    h=rmax-rmin+1
    w=cmax-cmin+1
    comp_info.append((h,w,rmin,cmin))
comp_info

def get_hor_runs(grid,color):
    lens=[]
    for r,row in enumerate(grid):
        cnt=0
        for c,v in enumerate(row):
            if v==color:
                cnt+=1
            else:
                if cnt>0:
                    lens.append((cnt,r,c-cnt))
                    cnt=0
        if cnt>0:
            lens.append((cnt,r,W-cnt))
    return lens
runs=get_hor_runs(grid_test,8)
min_len=min(l[0] for l in runs)
min_len

def get_ver_runs(grid,color):
    lens=[]
    H,W=grid.shape
    for c in range(W):
        cnt=0
        for r in range(H):
            if grid[r,c]==color:
                cnt+=1
            else:
                if cnt>0:
                    lens.append((cnt,r-cnt,c))
                    cnt=0
        if cnt>0:
            lens.append((cnt,H-cnt,c))
    return lens
vruns=get_ver_runs(grid_test,8)
min_vlen=min(l[0] for l in vruns)
