def unique_rect_min(grid,color):
    H,W=grid.shape
    best=None
    for area in range(4, H*W+1): #minimum area 2x2=4
        for hsize in range(2,H+1):
            if area%hsize!=0: continue
            wsize=area//hsize
            if wsize>W or wsize<2: continue
            count,pos=count_blocks(grid,color,hsize,wsize)
            if count==1:
                return hsize,wsize,pos
    return None
